<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function runTool(){const salario=parseFloat(document.getElementById('ir-salario').value);const inss=parseFloat(document.getElementById('ir-inss').value)||0;const dependentes=parseInt(document.getElementById('ir-dependentes').value||'0',10);clearError();if(isNaN(salario)||salario<=0||isNaN(inss)||inss<0||isNaN(dependentes)||dependentes<0){showError('Preencha salário, INSS e dependentes com valores válidos.');return;}const deducaoDependente=189.59*dependentes;const base=Math.max(0,salario-inss-deducaoDependente);let imposto=0;if(base<=2259.20){imposto=0;}else if(base<=2826.65){imposto=(base*0.075)-169.44;}else if(base<=3751.05){imposto=(base*0.15)-381.44;}else if(base<=4664.68){imposto=(base*0.225)-662.77;}else{imposto=(base*0.275)-896.00;}imposto=Math.max(0,imposto);document.getElementById('ir-base').textContent='R$ '+fmtBRL(base);document.getElementById('ir-valor').textContent='R$ '+fmtBRL(imposto);document.getElementById('tool-detail').textContent='Estimativa simplificada de IR mensal para apoio de planejamento.';showResult('tool-result');}function clearTool(){['ir-salario','ir-inss','ir-dependentes'].forEach(id=>document.getElementById(id).value='');['ir-base','ir-valor'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule o imposto antes de copiar o resultado.');return;}copyToClipboard('Base: '+document.getElementById('ir-base').textContent+'\nImposto estimado: '+document.getElementById('ir-valor').textContent,button);}
</script>
